const msg = $input.first().json;
const text = (msg.message?.text || msg.channel_post?.text || '').trim();
const chatId = String(msg.message?.chat?.id || msg.channel_post?.chat?.id || '');
const messageId = msg.message?.message_id || msg.channel_post?.message_id || 0;
const hoje = new Date().toISOString().split('T')[0];
return [{ json: { rawText: text, chatId, messageId, prompt: 'Analise a mensagem financeira e retorne JSON com: valor (numero), descricao (string curta), tipo (Entrada ou Saida), data (YYYY-MM-DD, hoje=' + hoje + '). Retorne APENAS JSON puro sem markdown. Mensagem: ' + text } }];

options.systemMessage:
Você é um assistente financeiro. Analise a mensagem e retorne APENAS um JSON válido.

Formato: {"valor":50,"descricao":"string","tipo":"Saida","categoria":"string","metodo":"string","data":"YYYY-MM-DD"}

Regras de DESCRIÇÃO: Inclua SEMPRE o local/estabelecimento se mencionado. Exemplos: 'jantar no Brooks' → 'Jantar no Brooks', 'almoço no McDonald's' → 'Almoço no McDonald's', 'uber para casa' → 'Uber para casa'.

Regras de TIPO: 'Entrada' = salário/renda/receita/ganho. 'Saida' = gasto/compra/despesa.

Regras de CATEGORIA (use exatamente um): '🍽️ Alimentação', '🚌 Transporte', '🎉 Lazer', '💊 Saúde', '📚 Educação', '🏠 Moradia', '🛒 Compras', '💰 Investimento', '📦 Outros'

Regras de MÉTODO: Se mencionar 'cartão' ou 'crédito' sem especificar qual banco → use 'PERGUNTA_CARTAO'. Se mencionar Nubank → '💜 Nubank'. Se C6 → '⚫ C6 Bank'. Se Itaú → '🟧 Itaú'. Se Bradesco → '🔴 Bradesco'. Se débito → '💳 Débito'. Se pix/transferência → '📱 Pix'. Se dinheiro/espécie → '💵 Dinheiro'. Se nada informado → '📱 Pix'.

Exemplos:
'50 almoço' → {"valor":50,"descricao":"Almoço","tipo":"Saida","categoria":"🍽️ Alimentação","metodo":"📱 Pix","data":"2026-02-21"}
'jantar no Brooks 80 cartão' → {"valor":80,"descricao":"Jantar no Brooks","tipo":"Saida","categoria":"🍽️ Alimentação","metodo":"PERGUNTA_CARTAO","data":"2026-02-21"}
'300 passeio cartão nubank' → {"valor":300,"descricao":"Passeio","tipo":"Saida","categoria":"🎉 Lazer","metodo":"💜 Nubank","data":"2026-02-21"}
'1500 salário' → {"valor":1500,"descricao":"Salário","tipo":"Entrada","categoria":"💰 Investimento","metodo":"📱 Pix","data":"2026-02-21"}

Retorne APENAS o JSON puro, sem markdown, sem texto.

parameters.jsCode:
const aiOutput = ($input.first().json.output || '').trim();
let parsed;
try {
  parsed = JSON.parse(aiOutput.replace(/```json|```/g, '').trim());
} catch(e) {
  const m = aiOutput.match(/\{[\s\S]*?\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(e2) { throw new Error('JSON invalido: ' + aiOutput); } }
  else throw new Error('Sem JSON: ' + aiOutput);
}
const prep = $node.FinancePrepare.json;
const valor = parseFloat(String(parsed.valor).replace(',', '.')) || 0;
const valorFormatado = valor.toFixed(2).replace('.', ',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');
const dataBruta = parsed.data || new Date().toISOString().split('T')[0];
const partes = dataBruta.split('-');
const dataFormatada = partes[2] + '/' + partes[1] + '/' + partes[0];
const tipo = (parsed.tipo || 'Saida').includes('Entrada') ? 'Entrada' : 'Saida';
const metodo = parsed.metodo || '📱 Pix';
const categoria = parsed.categoria || '📦 Outros';
return [{ json: { valor, valorFormatado, descricao: parsed.descricao || 'Sem descricao', tipo, categoria, metodo, data: dataBruta, dataFormatada, chatId: prep.chatId, messageId: prep.messageId } }];

