const cb = $input.first().json.callback_query;
if (!cb) return [];
const chatId = String(cb.message.chat.id);
const cardCode = (cb.data || '').replace('card:', '');
const questionMsgId = cb.message.message_id;
const cbQueryId = cb.id;
const cardMap = { 'Nubank': '💜 Nubank', 'C6': '⚫ C6 Bank', 'Itau': '🟧 Itaú', 'Brad': '🔴 Bradesco', 'Outro': '💳 Outro Cartão' };
const metodo = cardMap[cardCode] || '💳 ' + cardCode;
const pending = ($workflow.staticData.pending || {})[chatId];
if (!pending) throw new Error('Transacao pendente nao encontrada');
delete $workflow.staticData.pending[chatId];
const BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';
await fetch('https://api.telegram.org/bot' + BOT_TOKEN + '/answerCallbackQuery', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ callback_query_id: cbQueryId, text: 'Registrando...' }) });
return [{ json: { ...pending, metodo, questionMsgId, chatId } }];

const data = $input.first().json;
const chatId = String(data.chatId);
const BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';
const resp = await fetch('https://api.telegram.org/bot' + BOT_TOKEN + '/sendMessage', { method: 'POST', headers: {'Content-Type': 'application/json'}, body: JSON.stringify({ chat_id: chatId, text: '💳 <b>Qual cartão você usou?</b>', parse_mode: 'HTML', reply_markup: { inline_keyboard: [
  [{ text: '💜 Nubank', callback_data: 'card:Nubank' }, { text: '⚫ C6 Bank', callback_data: 'card:C6' }],
  [{ text: '🟧 Itaú', callback_data: 'card:Itau' }, { text: '🔴 Bradesco', callback_data: 'card:Brad' }],
  [{ text: '💳 Outro', callback_data: 'card:Outro' }]
] } }) });
const result = await resp.json();
const questionMsgId = result.result?.message_id || 0;
$workflow.staticData.pending = $workflow.staticData.pending || {};
$workflow.staticData.pending[chatId] = { valor: data.valor, valorFormatado: data.valorFormatado, descricao: data.descricao, tipo: data.tipo, categoria: data.categoria, data: data.data, dataFormatada: data.dataFormatada, chatId, messageId: data.messageId, questionMsgId };
return [{ json: { ok: true, chatId, questionMsgId } }];

const msg = $input.first().json.message;
const photos = msg.photo;
// Usa foto de resolucao media (indice 1 ou ultimo)
const photo = photos[Math.min(1, photos.length - 1)];
const chatId = msg.chat.id;
const messageId = msg.message_id;
const caption = msg.caption || '';
const BOT_TOKEN = '<TELEGRAM_BOT_TOKEN>';

// Obtem caminho do arquivo no Telegram
const fileInfoResp = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/getFile?file_id=${photo.file_id}`);
const fileInfo = await fileInfoResp.json();
const filePath = fileInfo.result.file_path;

// Faz download e converte para base64
const imageResp = await fetch(`https://api.telegram.org/file/bot${BOT_TOKEN}/${filePath}`);
const arrayBuf = await imageResp.arrayBuffer();
const base64 = Buffer.from(arrayBuf).toString('base64');
const mimeType = filePath.toLowerCase().endsWith('.png') ? 'image/png' : 'image/jpeg';

return [{ json: { base64Image: base64, mimeType, chatId, messageId, caption } }];

const resp = $input.first().json;
const aiOutput = (resp.choices?.[0]?.message?.content || '').trim();
const photoData = $node.PreparePhotoData.json;

let parsed;
try {
  parsed = JSON.parse(aiOutput.replace(/```json|```/g, '').trim());
} catch(e) {
  const m = aiOutput.match(/\{[\s\S]*?\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(e2) { throw new Error('JSON invalido: ' + aiOutput); } }
  else throw new Error('Sem JSON na resposta: ' + aiOutput);
}

const valor = parseFloat(String(parsed.valor).replace(',', '.')) || 0;
const valorFormatado = valor.toFixed(2).replace('.', ',').replace(/\B(?=(\d{3})+(?!\d))/g, '.');
const dataBruta = parsed.data || new Date().toISOString().split('T')[0];
const partes = dataBruta.split('-');
const dataFormatada = partes[2] + '/' + partes[1] + '/' + partes[0];
const tipo = (parsed.tipo || 'Saida').includes('Entrada') ? 'Entrada' : 'Saida';
const metodo = parsed.metodo || '📱 Pix';
const catRaw = parsed.categoria || 'Outros';
const catMap = { 'Alimentacao': '🍽️ Alimentação', 'Transporte': '🚌 Transporte', 'Lazer': '🎉 Lazer', 'Saude': '💊 Saúde', 'Educacao': '📚 Educação', 'Moradia': '🏠 Moradia', 'Compras': '🛒 Compras', 'Investimento': '💰 Investimento', 'Outros': '📦 Outros' };
const categoria = catMap[catRaw] || '📦 Outros';

return [{ json: { valor, valorFormatado, descricao: parsed.descricao || 'Comprovante', tipo, categoria, metodo, data: dataBruta, dataFormatada, chatId: photoData.chatId, messageId: photoData.messageId, questionMsgId: 0 } }];

const msg = $input.first().json;
const text = (msg.message?.text || msg.channel_post?.text || '').trim();
const ideia = text.replace(/^!\s*/, '');
const chatId = String(msg.message?.chat?.id || msg.channel_post?.chat?.id || '');
const messageId = msg.message?.message_id || msg.channel_post?.message_id || 0;
return [{ json: { ideia, chatId, messageId, data: new Date().toISOString().split('T')[0] } }];

